import{_ as t,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"플랫폼 기능: 계획 및 코드 리뷰 | Plannotator","description":"Plannotator의 플랫폼 기능을 학습하세요. 계획 리뷰와 코드 리뷰를 포함합니다. 시각적 리뷰, 주석 추가, 이미지 어노테이션 등 핵심 기술을 마스터하세요.","frontmatter":{"title":"플랫폼 기능: 계획 및 코드 리뷰 | Plannotator","sidebarTitle":"AI 계획 및 코드 리뷰","subtitle":"플랫폼 기능: 계획 및 코드 리뷰","description":"Plannotator의 플랫폼 기능을 학습하세요. 계획 리뷰와 코드 리뷰를 포함합니다. 시각적 리뷰, 주석 추가, 이미지 어노테이션 등 핵심 기술을 마스터하세요.","order":2},"headers":[],"relativePath":"ko/backnotprop/plannotator/platforms/index.md","filePath":"ko/backnotprop/plannotator/platforms/index.md"}'),i={name:"ko/backnotprop/plannotator/platforms/index.md"};function n(l,a,d,s,h,c){return o(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="플랫폼-기능" tabindex="-1">플랫폼 기능 <a class="header-anchor" href="#플랫폼-기능" aria-label="Permalink to &quot;플랫폼 기능&quot;">​</a></h1><p>이 장에서는 Plannotator의 두 가지 핵심 기능인 <strong>계획 리뷰</strong>와 <strong>코드 리뷰</strong>를 소개합니다. AI가 생성한 계획을 시각적으로 리뷰하는 방법, 다양한 주석 추가, 이미지 어노테이션 첨부, 그리고 git diff 코드 변경 사항 리뷰 방법을 배우게 됩니다.</p><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">시작 전 확인</p><p>이 장을 학습하기 전에 다음 사항을 확인하세요:</p><ul><li>✅ <a href="./../start/getting-started/">빠른 시작</a> 튜토리얼 완료</li><li>✅ Plannotator 플러그인 설치 완료 (<a href="./../start/installation-claude-code/">Claude Code</a> 또는 <a href="./../start/installation-opencode/">OpenCode</a>)</li></ul></div><h2 id="이-장-내용" tabindex="-1">이 장 내용 <a class="header-anchor" href="#이-장-내용" aria-label="Permalink to &quot;이 장 내용&quot;">​</a></h2><h3 id="계획-리뷰" tabindex="-1">계획 리뷰 <a class="header-anchor" href="#계획-리뷰" aria-label="Permalink to &quot;계획 리뷰&quot;">​</a></h3><p>AI가 생성한 실행 계획을 리뷰하고 수정 제안을 추가하여 AI가 의도한 대로 실행하도록 하는 방법을 학습합니다.</p><table tabindex="0"><thead><tr><th>튜토리얼</th><th>설명</th></tr></thead><tbody><tr><td><a href="./plan-review-basics/">계획 리뷰 기초</a></td><td>Plannotator를 사용하여 AI가 생성한 계획을 시각적으로 리뷰하고 계획 승인 또는 거부하는 방법 학습</td></tr><tr><td><a href="./plan-review-annotations/">계획 주석 추가</a></td><td>계획에 다양한 유형의 주석(삭제, 교체, 삽입, 코멘트)을 추가하는 방법 마스터</td></tr><tr><td><a href="./plan-review-images/">이미지 어노테이션 추가</a></td><td>계획 리뷰에 이미지를 첨부하고 브러시, 화살표, 원형 도구를 사용하여 어노테이션을 추가하는 방법 학습</td></tr></tbody></table><h3 id="코드-리뷰" tabindex="-1">코드 리뷰 <a class="header-anchor" href="#코드-리뷰" aria-label="Permalink to &quot;코드 리뷰&quot;">​</a></h3><p>코드 변경 사항을 리뷰하고 행 단위 주석을 추가하여 커밋 전에 문제를 발견하는 방법을 학습합니다.</p><table tabindex="0"><thead><tr><th>튜토리얼</th><th>설명</th></tr></thead><tbody><tr><td><a href="./code-review-annotations/">코드 주석 추가</a></td><td>코드 리뷰에서 행 단위 주석(comment/suggestion/concern)을 추가하는 방법 마스터</td></tr><tr><td><a href="./code-review-diff-types/">Diff 뷰 전환</a></td><td>코드 리뷰에서 다른 diff 타입(uncommitted/staged/last commit/branch)으로 전환하는 방법 학습</td></tr></tbody></table><h2 id="학습-경로" tabindex="-1">학습 경로 <a class="header-anchor" href="#학습-경로" aria-label="Permalink to &quot;학습 경로&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">권장 학습 순서</p><p>사용 시나리오에 따라 적절한 학습 경로를 선택하세요:</p><p><strong>경로 A: 계획 리뷰 우선</strong> (초보자 권장)</p><ol><li><a href="./plan-review-basics/">계획 리뷰 기초</a> → 기본적인 계획 리뷰 프로세스 먼저 학습</li><li><a href="./plan-review-annotations/">계획 주석 추가</a> → 계획을 정밀하게 수정하는 방법 학습</li><li><a href="./plan-review-images/">이미지 어노테이션 추가</a> → 이미지로 의도를 더 명확하게 표현</li><li>그 후 코드 리뷰 시리즈 학습</li></ol><p><strong>경로 B: 코드 리뷰 우선</strong> (Code Review 경험이 있는 개발자에게 적합)</p><ol><li><a href="./code-review-basics/">코드 리뷰 기초</a> → 코드 리뷰 인터페이스 익숙해지기</li><li><a href="./code-review-annotations/">코드 주석 추가</a> → 행 단위 주석 학습</li><li><a href="./code-review-diff-types/">Diff 뷰 전환</a> → 다른 diff 타입 마스터</li><li>그 후 계획 리뷰 시리즈 학습</li></ol></div><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장을 완료한 후 다음을 계속 학습할 수 있습니다:</p><ul><li><a href="./../advanced/url-sharing/">URL 공유</a> - URL을 통해 계획과 주석을 공유하여 팀 협업 구현</li><li><a href="./../advanced/obsidian-integration/">Obsidian 통합</a> - 승인된 계획을 Obsidian에 자동 저장</li><li><a href="./../advanced/remote-mode/">원격 모드</a> - SSH, devcontainer, WSL 환경에서 Plannotator 사용</li></ul>',16)])])}const b=t(i,[["render",n]]);export{f as __pageData,b as default};
